bool CarFilter::filter(
  const autoware_perception_msgs::msg::Shape & shape,
  [[maybe_unused]] const geometry_msgs::msg::Pose & pose)
{
  constexpr float min_width = 1.2;
  constexpr float max_width = 2.5;
  constexpr float max_length = 5.8;
  return utils::filterVehicleBoundingBox(shape, min_width, max_width, max_length);
}

bool filterVehicleBoundingBox(
  const autoware_perception_msgs::msg::Shape & shape, const float min_width, const float max_width,
  const float max_length);
}  // namespace utils

}  // namespace autoware::shape_estimation

#endif  // AUTOWARE__SHAPE_ESTIMATION__FILTER__UTILS_HPP_

bool filterVehicleBoundingBox(
  const autoware_perception_msgs::msg::Shape & shape, const float min_width, const float max_width,
  const float max_length)
{
  const float x = shape.dimensions.x;
  const float y = shape.dimensions.y;
  const float s = x * y;

  if (shape.type != autoware_perception_msgs::msg::Shape::BOUNDING_BOX) {
    return true;
  }
  if (x < min_width && y < min_width) {
    return false;
  }
  if (max_width < x && max_width < y) {
    return false;
  }

  if (max_length < x || max_length < y) {
    return false;
  }

  if (max_length * max_width < s) {
    return false;
  }
  return true;
}
